preprocess.style:
async ({ attributes, content, filename = '' }) => {
		const ext = attributes.lang ? `.${attributes.lang}` : '.css';
		if (attributes.lang && !isCSSRequest(ext)) return;
		if (!cssTransform) {
			cssTransform = createCssTransform(style, config).then((t) => (cssTransform = t));
		}
		const transform = await cssTransform;
		const suffix = `${lang_sep}${ext}`;
		const moduleId = `${filename}${suffix}`;
		const { code, map, deps } = await transform(content, moduleId);
		removeLangSuffix(map, suffix);
		mapToRelative(map, filename);
		const dependencies = deps ? Array.from(deps).filter((d) => !d.endsWith(suffix)) : undefined;
		return {
			code,
			map: map ?? undefined,
			dependencies
		};
	}

preprocess.markup:
({ content, filename }) => {
		if (process.env.NODE_ENV !== 'production') {
			return { code: content };
		}

		const classMap = {};
		filenamesMap[filename] = classMap;

		const regex1 = /class="([^"]*?)"/g;
		let output = content.replace(regex1, (match, classNames) => {
			const newClassNames = classNames
				.split(' ')
				.map((cls) => {
					if (classMap[cls]) {
						return classMap[cls];
					} else {
						const newClass = getUniqueClassName(new Set(Object.values(classMap)));
						classMap[cls] = newClass;
						return newClass;
					}
				})
				.join(' ');

			return 'class="' + newClassNames + '"';
		});

		const regex2 = /class={{([^"]*?)}}/g;
		output = output.replace(regex2, (match, classNames) => {
			const regexClassName = /([\w]+:)+/g;

			const newClassNames = classNames.replace(regexClassName, (cls) => {
				const className = cls.trim().slice(0, -1);

				if (classMap[className]) {
					return classMap[className] + ':';
				} else {
					const newClass = getUniqueClassName(new Set(Object.values(classMap)));
					classMap[className] = newClass;
					return newClass + ':';
				}
			});

			return 'class={{' + newClassNames + '}}';
		});

		return {
			code: output
		};
	}

preprocess.style:
({ content, filename }) => {
		if (process.env.NODE_ENV !== 'production') {
			return { code: content };
		}

		const classNames = filenamesMap[filename] || {};

		const regex = /(?<!:global\()\.[a-zA-Z]+(?:[-_][a-zA-Z0-9]+)*(?:__[a-zA-Z0-9_-]+)?/g;

		// Заменяем классы и сохраняем их в мапу
		const newCode = content.replace(regex, (match) => {
			const cls = match.slice(1);
			if (classNames[cls]) {
				return '.' + classNames[cls];
			}

			return match;
		});

		return {
			code: newCode
		};
	}
